152→    // Zoom centered on cursor
153→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
154→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
