 19→function EditorShell({
 20→  project,
 21→  handleNew,
 22→  handleSave,
 23→  handleLoadClick,
 24→  isSidebarCollapsed,
 25→  isPropertiesCollapsed,
 26→  onToggleSidebar,
 27→  onToggleProperties,
 28→}) {
 29→  const {
 30→    workspaceMode,
 31→    activeSheetId,
 32→    activeFloorId,
 33→    dispatch: editorDispatch,
 34→  } = useEditor();
 35→
 36→  useEffect(() => {
 37→    const sheets = project.sheets || [];
 38→    if (!sheets.length) {
 39→      if (activeSheetId !== null) {
 40→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
