118→export function getDefaultViewportRect(sheet, source, scale = 100) {
119→  const paper = getPaperPreset(sheet.paperSize);
120→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
121→  const denom = Math.max(1, scale);
122→  const width = Math.max(70, Math.min((bounds.maxX - bounds.minX) / denom + CONTENT_PADDING * 2, paper.width - SHEET_MARGIN * 2));
123→  const height = Math.max(50, Math.min((bounds.maxY - bounds.minY) / denom + CONTENT_PADDING * 2, paper.height - SHEET_MARGIN * 2 - TITLE_BLOCK_HEIGHT));
124→  return {
125→    x: SHEET_MARGIN + 8,
126→    y: SHEET_MARGIN + 8,
127→    width,
128→    height,
129→  };
130→}
